// Baut eine Discord Alert-Message für den Eskalations-Channel.
// Input-Schema (von discord_notify.py in ai-review-pipeline):
//   body.alert_type   'escalation' | 'disagreement' | 'soft_consensus'
//   body.pr           string | number
//   body.pr_url       string
//   body.project      string
//   body.stage        string (für escalation)
//   body.iterations   number
//   body.last_score   number | null
//   body.summary      string (max 500 Zeichen)
//   body.runbook_url  string
//   body.rerun_cmd    string
//   body.codex        {verdict, score} (für disagreement)
//   body.cursor       {verdict, score} (für disagreement)
//   body.avg_score    number (für soft_consensus)
//   body.codex_score  number (für soft_consensus)
//   body.cursor_score number (für soft_consensus)
//   body.options      {approve, retry, timeout_minutes} (für soft_consensus)
//
// Ziel-Channel: DISCORD_ALERTS_CHANNEL_ID (aus env) oder body.channel_id
// Mention: @here bei echten Eskalationen

const body = $json.body ?? $json ?? {};

const alertType = body.alert_type ?? body.event ?? 'escalation';
const pr        = body.pr ?? '?';
const prUrl     = body.pr_url ?? '';
const project   = body.project ?? '';
const runbook   = body.runbook_url ?? '';
const rerun     = body.rerun_cmd ?? '';

// Channel: explizit im Payload oder Fallback auf ALERTS_CHANNEL_ID env-var
const channelId = String(
  body.channel_id ??
  $env.DISCORD_ALERTS_CHANNEL_ID ??
  ''
);

if (!channelId) {
  throw new Error(
    'channel_id fehlt im Payload und DISCORD_ALERTS_CHANNEL_ID nicht gesetzt. ' +
    'Bitte .ai-review/config.yaml oder ~/.config/ai-workflows/env prüfen.'
  );
}

const stageEmoji = {
  code: '\ud83e\udd16',
  'code-cursor': '\ud83d\udc31',
  security: '\ud83d\udd12',
  design: '\ud83c\udfa8',
};

let content;
let shouldMention = true;  // @here bei echten Eskalationen

if (alertType === 'soft_consensus' || alertType === 'ai-review/soft-consensus') {
  shouldMention = false;  // soft_consensus = keine @here-Mention
  const codexScore  = body.codex_score ?? '-';
  const cursorScore = body.cursor_score ?? '-';
  const avg         = body.avg_score ?? '?';
  const opts        = body.options ?? {};

  content = [
    `\u{1F914} **AI-Review soft-consensus** \u2014 PR #${pr}`,
    project ? `Projekt: \`${project}\`` : '',
    '',
    `\u{1F916} Codex: **${codexScore}/10**`,
    `\ud83d\udc31 Cursor: **${cursorScore}/10**`,
    `\ud83d\udcca Avg: **${avg}/10** (soft-zone 5\u20138)`,
    '',
    'Die Code-Reviewer sehen es differenziert. Bitte kurz reinschauen.',
    '',
    prUrl ? `**PR:** ${prUrl}` : '',
    '',
    opts.approve ? `\u2705 Approve: \`${opts.approve}\`` : '',
    opts.retry   ? `\ud83d\udd01 Retry: \`${opts.retry}\`` : '',
    opts.timeout_minutes ? `\u23f1\ufe0f Auto-Eskalation in ${opts.timeout_minutes} min` : '',
    runbook ? `\ud83d\udcd6 Runbook: ${runbook}` : '',
  ].filter(Boolean).join('\n');

} else if (alertType === 'disagreement' || alertType === 'ai-review/disagreement') {
  const codex  = body.codex ?? {};
  const cursor = body.cursor ?? {};
  const fmt    = r => `${r.verdict ?? '?'} (${r.score ?? '-'}/10)`;

  content = [
    `\u{1F914} **AI-Review Disagreement** \u2014 PR #${pr}`,
    project ? `Projekt: \`${project}\`` : '',
    '@here',
    '',
    `\u{1F916} Codex: **${fmt(codex)}**`,
    `\ud83d\udc31 Cursor: **${fmt(cursor)}**`,
    '',
    'Die beiden Code-Reviewer sind uneinig. Bitte kurz reinschauen.',
    '',
    prUrl ? `**PR:** ${prUrl}` : '',
    rerun   ? `\u2022 Re-Trigger: \`${rerun}\`` : '',
    runbook ? `\u2022 Runbook: ${runbook}` : '',
  ].filter(Boolean).join('\n');

} else {
  // Standard: Circuit-Breaker Eskalation
  const stage      = body.stage ?? 'unknown';
  const iterations = body.iterations ?? '?';
  const lastScore  = body.last_score ?? null;
  const summary    = String(body.summary ?? '').slice(0, 500);
  const stageE     = stageEmoji[stage] || '\u2699\ufe0f';
  const scoreLine  = lastScore !== null && lastScore !== undefined
    ? `**Score:** ${lastScore}/10`
    : '';

  content = [
    `\u26a0\ufe0f **AI Review Escalation** @here`,
    project ? `Projekt: \`${project}\`` : '',
    '',
    `${stageE} **Stage:** ${stage}`,
    `**PR:** #${pr}`,
    scoreLine,
    `**Iterations:** ${iterations} (circuit-breaker)`,
    '',
    summary ? `**Letzter Hinweis:**\n\`\`\`\n${summary}\n\`\`\`` : '',
    '',
    prUrl   ? `**PR:** ${prUrl}` : '',
    rerun   ? `\u2022 Re-Trigger: \`${rerun}\`` : '',
    runbook ? `\u2022 Runbook: ${runbook}` : '',
  ].filter(Boolean).join('\n');
}

return [{
  json: {
    channel_id: channelId,
    content,
    alert_type: alertType,
    pr_number: String(pr),
  },
}];
